function solve(n) {
    function toBase36(num) {
        if (num === 0) return '0';
        const digits = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
        let result = '';
        while (num > 0) {
            let remainder = num % 36;
            result = digits[remainder] + result;
            num = Math.floor(num / 36);
        }
        return result;
    }

    let n2 = n * n;
    let n3 = n * n * n;

    let hexStr = n2.toString(16).toUpperCase();
    let base36Str = toBase36(n3);

    return hexStr + base36Str;
}

