def solve(n: Long): String = {
  def toBase36(num: Long): String = {
    if (num == 0) "0"
    else {
      val digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
      var result = ""
      var numCopy = num
      while (numCopy > 0) {
        val remainder = numCopy % 36
        result = digits(remainder) + result
        numCopy = numCopy / 36
      }
      result
    }
  }

  val n2 = n * n
  val n3 = n * n * n

  val hexStr = n2.toString(16).toUpperCase
  val base36Str = toBase36(n3)

  hexStr + base36Str
}
```

